/**
 * Lightweight POST-based SSE client.
 *
 * Standard EventSource only supports GET, so this uses fetch + ReadableStream
 * to consume SSE events from a POST endpoint. Parses the `event:` / `data:`
 * fields and dispatches typed callbacks.
 */

import type { DecomposeModule, DecomposeEvent } from '$lib/schemas/decompose.js';

// ── Types ───────────────────────────────────────────────────────────────────

export interface PostSseCallbacks {
	onModule?: (index: number, module: DecomposeModule) => void;
	onError?: (stage: string, message: string) => void;
	onDone?: (total: number, errors: number) => void;
}

export interface PostSseResult {
	abort: () => void;
}

// ── SSE parser ──────────────────────────────────────────────────────────────

/**
 * Parse a raw SSE text buffer into individual events.
 * Handles the standard SSE format: `event: <name>\ndata: <json>\n\n`.
 *
 * Returns parsed events and any leftover text that may be an incomplete event.
 */
function parseSseBuffer(buffer: string): { events: DecomposeEvent[]; remaining: string } {
	const events: DecomposeEvent[] = [];
	const parts = buffer.split('\n\n');
	// The last part may be incomplete (no trailing \n\n yet)
	const remaining = parts.pop() ?? '';

	for (const part of parts) {
		const event = parseSingleSseEvent(part.trim());
		if (event) events.push(event);
	}

	return { events, remaining };
}

function parseSingleSseEvent(block: string): DecomposeEvent | null {
	let eventType = '';
	let dataStr = '';

	for (const line of block.split('\n')) {
		if (line.startsWith('event:')) {
			eventType = line.slice(6).trim();
		} else if (line.startsWith('data:')) {
			dataStr = line.slice(5).trimStart();
		}
	}

	if (!dataStr) return null;

	try {
		const parsed = JSON.parse(dataStr) as DecomposeEvent;
		// Prefer the SSE event field; fallback to the parsed type field
		if (eventType && !parsed.type) {
			(parsed as any).type = eventType;
		}
		return parsed;
	} catch {
		console.warn('[sse-client] Failed to parse SSE data:', dataStr.slice(0, 200));
		return null;
	}
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Send a POST request and consume the response as an SSE stream.
 *
 * @param url      - The endpoint URL
 * @param body     - The JSON body to POST
 * @param callbacks - Event callbacks (onModule, onError, onDone)
 * @returns An object with an `abort()` method to cancel the stream
 */
export function postSse(url: string, body: Record<string, unknown>, callbacks: PostSseCallbacks): PostSseResult {
	const controller = new AbortController();
	let buffer = '';

	fetch(url, {
		method: 'POST',
		headers: { 'Content-Type': 'application/json' },
		body: JSON.stringify(body),
		signal: controller.signal
	})
		.then(async (response) => {
			if (!response.ok) {
				// Server returned a non-200 before streaming started
				const errorBody = await response.text().catch(() => 'Unknown error');
				callbacks.onError?.('connecting', `HTTP ${response.status}: ${errorBody.slice(0, 500)}`);
				callbacks.onDone?.(0, 1);
				return;
			}

			const reader = response.body?.getReader();
			if (!reader) {
				callbacks.onError?.('connecting', 'Response body is not readable');
				callbacks.onDone?.(0, 1);
				return;
			}

			const decoder = new TextDecoder();

			try {
				while (true) {
					const { done, value } = await reader.read();
					if (done) break;

					buffer += decoder.decode(value, { stream: true });
					const { events, remaining } = parseSseBuffer(buffer);
					buffer = remaining;

					for (const event of events) {
						switch (event.type) {
							case 'module':
								callbacks.onModule?.(event.index, event.module);
								break;
							case 'error':
								callbacks.onError?.(event.stage, event.message);
								break;
							case 'done':
								callbacks.onDone?.(event.total, event.errors);
								break;
						}
					}
				}

				// Process any remaining buffer (final chunk)
				if (buffer.trim()) {
					const { events } = parseSseBuffer(buffer + '\n\n');
					for (const event of events) {
						switch (event.type) {
							case 'module':
								callbacks.onModule?.(event.index, event.module);
								break;
							case 'error':
								callbacks.onError?.(event.stage, event.message);
								break;
							case 'done':
								callbacks.onDone?.(event.total, event.errors);
								break;
						}
					}
				}
			} catch (err: any) {
				if (err.name !== 'AbortError') {
					callbacks.onError?.('streaming', err.message ?? 'Stream read error');
					callbacks.onDone?.(0, 1);
				}
			}
		})
		.catch((err: any) => {
			if (err.name !== 'AbortError') {
				callbacks.onError?.('connecting', err.message ?? 'Network error');
				callbacks.onDone?.(0, 1);
			}
		});

	return { abort: () => controller.abort() };
}

import { redirect, error } from '@sveltejs/kit';
import type { PageServerLoad } from './$types.js';
import { db } from '$lib/db/index.js';
import { getMilestone } from '$lib/server/milestone-service.js';

export const load: PageServerLoad = async ({ params }) => {
	const milestone = await getMilestone(db, params.id);

	if (!milestone) {
		throw error(404, `里程碑 ${params.id} 不存在`);
	}

	// Only allow preview for draft milestones
	if (milestone.status !== 'draft') {
		throw redirect(302, `/milestones/${params.id}`);
	}

	return {
		milestone: {
			id: milestone.id,
			title: milestone.title,
			sourceMd: milestone.sourceMd ?? null,
			status: milestone.status,
			createdAt: milestone.createdAt
		}
	};
};

/**
 * POST /api/milestones/:id/confirm
 *
 * Confirms a milestone's decomposed modules and tasks.
 * Validates body with confirmRequestSchema, calls confirmService,
 * returns JSON with created module/task IDs.
 */

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { db } from '$lib/db/index.js';
import { getMilestone } from '$lib/server/milestone-service.js';
import { confirmMilestone } from '$lib/server/confirm-service.js';
import { confirmRequestSchema } from '$lib/schemas/confirm.js';

// ── Handler ──────────────────────────────────────────────────────────────────

export const POST: RequestHandler = async ({ params, request }) => {
	// Parse and validate request body
	let body: unknown;
	try {
		body = await request.json();
	} catch {
		return json(
			{ error: { code: 'bad_request', message: 'Invalid JSON body' } },
			{ status: 400 }
		);
	}

	const parsed = confirmRequestSchema.safeParse(body);
	if (!parsed.success) {
		const details = parsed.error.issues.map((i) => ({
			field: i.path.join('.'),
			message: i.message
		}));
		return json(
			{ error: { code: 'validation_error', message: 'Request validation failed', details } },
			{ status: 400 }
		);
	}

	// Check milestone exists
	const milestone = await getMilestone(db, params.id);
	if (!milestone) {
		return json(
			{ error: { code: 'not_found', message: `Milestone ${params.id} not found` } },
			{ status: 404 }
		);
	}

	// Check status is draft
	if (milestone.status !== 'draft') {
		return json(
			{ error: { code: 'bad_request', message: `Milestone status is '${milestone.status}', expected 'draft'` } },
			{ status: 400 }
		);
	}

	// Execute confirm
	const result = await confirmMilestone(db, params.id, parsed.data.modules);

	if ('error' in result) {
		const status = result.error.code === 'not_found' ? 404 : 400;
		return json({ error: result.error }, { status });
	}

	return json({
		milestoneId: params.id,
		modules: result.data
	});
};

/**
 * POST /api/milestones/:id/compare
 *
 * Streams LLM comparison of source markdown vs confirmed modules as SSE.
 * Validates milestone exists, then streams CompareEvents.
 */

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { db } from '$lib/db/index.js';
import { getMilestone } from '$lib/server/milestone-service.js';
import { streamCompare } from '$lib/server/compare-service.js';
import { compareRequestSchema } from '$lib/schemas/confirm.js';
import type { CompareEvent } from '$lib/schemas/confirm.js';

// ── SSE formatting helpers ──────────────────────────────────────────────────

function formatSSE(event: CompareEvent): string {
	return `event: ${event.type}\ndata: ${JSON.stringify(event)}\n\n`;
}

// ── Handler ──────────────────────────────────────────────────────────────────

export const POST: RequestHandler = async ({ params, request }) => {
	// Check milestone exists
	const milestone = await getMilestone(db, params.id);
	if (!milestone) {
		return json(
			{ error: { code: 'not_found', message: `Milestone ${params.id} not found` } },
			{ status: 404 }
		);
	}

	// Parse and validate request body
	let body: unknown;
	try {
		body = await request.json();
	} catch {
		return json(
			{ error: { code: 'bad_request', message: 'Invalid JSON body' } },
			{ status: 400 }
		);
	}

	const parsed = compareRequestSchema.safeParse(body);
	if (!parsed.success) {
		const details = parsed.error.issues.map((i) => ({
			field: i.path.join('.'),
			message: i.message
		}));
		return json(
			{ error: { code: 'validation_error', message: 'Request validation failed', details } },
			{ status: 400 }
		);
	}

	const sourceMd = milestone.sourceMd ?? '';

	// Stream SSE events from the compare service
	const generator = streamCompare(sourceMd, parsed.data.modules);

	const stream = new ReadableStream({
		async start(controller) {
			const encoder = new TextEncoder();
			try {
				for await (const event of generator) {
					controller.enqueue(encoder.encode(formatSSE(event)));
				}
				controller.close();
			} catch (err: any) {
				try {
					const errorEvent: CompareEvent = {
						type: 'error',
						stage: 'streaming',
						message: err.message
					};
					controller.enqueue(encoder.encode(formatSSE(errorEvent)));
					controller.close();
				} catch {
					// Controller already closed
				}
			}
		}
	});

	return new Response(stream, {
		headers: {
			'Content-Type': 'text/event-stream',
			'Cache-Control': 'no-cache',
			'Connection': 'keep-alive'
		}
	});
};

/**
 * Shared client-side state for decompose preview/edit flow.
 *
 * Stores pending decompose modules keyed by milestoneId so that
 * DecomposeStream → stores results → preview page reads them.
 *
 * Uses Svelte 5 runes for reactivity.
 */

import type { DecomposeModule } from '$lib/schemas/decompose.js';

// ── Types ────────────────────────────────────────────────────────────────────

/** Editable module with checked state for confirm selection. */
export interface EditableModule {
	name: string;
	description: string;
	checked: boolean;
	tasks: EditableTask[];
}

/** Editable task with checked state. */
export interface EditableTask {
	title: string;
	description: string;
	checked: boolean;
}

// ── State ────────────────────────────────────────────────────────────────────

const pendingMap = $state<Record<string, EditableModule[]>>({});

// ── Public API ───────────────────────────────────────────────────────────────

/** Store pending modules for a milestone. Converts DecomposeModule[] → EditableModule[]. */
export function setPendingModules(milestoneId: string, modules: DecomposeModule[]): void {
	pendingMap[milestoneId] = modules.map((m) => ({
		name: m.name,
		description: m.description ?? '',
		checked: true,
		tasks: m.tasks.map((t) => ({
			title: t.title,
			description: t.description ?? '',
			checked: true
		}))
	}));
}

/** Get pending modules for a milestone (or null if none stored). */
export function getPendingModules(milestoneId: string): EditableModule[] | null {
	return pendingMap[milestoneId] ?? null;
}

/** Clear pending modules for a milestone (e.g. after confirm). */
export function clearPendingModules(milestoneId: string): void {
	delete pendingMap[milestoneId];
}

/** Check whether a milestone has pending modules in the store. */
export function hasPendingModules(milestoneId: string): boolean {
	return (pendingMap[milestoneId]?.length ?? 0) > 0;
}

import { z } from 'zod';
import { milestoneIdSchema } from './common.js';

// ── Confirm request schema ───────────────────────────────────────────────────

/** A task within a confirmed module. */
export const confirmTaskSchema = z.object({
	title: z.string().min(1, 'Task title is required').max(500, 'Task title too long'),
	description: z.string().max(5000).optional()
});
export type ConfirmTask = z.infer<typeof confirmTaskSchema>;

/** A confirmed module with its tasks. */
export const confirmModuleSchema = z.object({
	name: z.string().min(1, 'Module name is required').max(200, 'Module name too long'),
	description: z.string().max(5000).optional(),
	tasks: z.array(confirmTaskSchema).min(1, 'Each module must have at least one task')
});
export type ConfirmModule = z.infer<typeof confirmModuleSchema>;

/** The full confirm request body. */
export const confirmRequestSchema = z.object({
	modules: z
		.array(confirmModuleSchema)
		.min(1, 'At least one module is required')
		.max(50, 'Too many modules')
});
export type ConfirmRequest = z.infer<typeof confirmRequestSchema>;

// ── Compare request schema ───────────────────────────────────────────────────

export const compareRequestSchema = z.object({
	modules: z
		.array(confirmModuleSchema)
		.min(1, 'At least one module is required')
});
export type CompareRequest = z.infer<typeof compareRequestSchema>;

// ── Confirm response types ───────────────────────────────────────────────────

export const confirmModuleResponseSchema = z.object({
	id: z.string(),
	milestoneId: z.string(),
	name: z.string(),
	description: z.string().nullable(),
	status: z.string(),
	sortOrder: z.number().int(),
	tasks: z.array(
		z.object({
			id: z.string(),
			shortId: z.number().int().positive(),
			moduleId: z.string(),
			title: z.string(),
			description: z.string().nullable(),
			status: z.string()
		})
	)
});
export type ConfirmModuleResponse = z.infer<typeof confirmModuleResponseSchema>;

// ── SSE event types for compare ──────────────────────────────────────────────

export type CompareEvent = CompareSuggestionEvent | CompareErrorEvent | CompareDoneEvent;

export interface CompareSuggestionEvent {
	type: 'suggestion';
	content: string;
}

export interface CompareErrorEvent {
	type: 'error';
	stage: 'connecting' | 'streaming';
	message: string;
}

export interface CompareDoneEvent {
	type: 'done';
}

// Simple toast notification system
// Usage in any component: import { toast } from '$lib/stores/toast'; toast.show('message', 'success');

interface ToastItem {
	id: number;
	message: string;
	type: 'success' | 'error' | 'info';
}

let toasts = $state<ToastItem[]>([]);
let nextId = $state(0);

function show(message: string, type: ToastItem['type'] = 'info', duration = 4000) {
	const id = nextId++;
	toasts.push({ id, message, type });
	setTimeout(() => {
		toasts = toasts.filter((t) => t.id !== id);
	}, duration);
}

export function getToasts() {
	return toasts;
}

export const toast = { show };

